import{_ as l,c as i,o as a,a4 as e}from"./chunks/framework.66Xi2WY6.js";const f=JSON.parse('{"title":"什么是架构师","description":"","frontmatter":{},"headers":[{"level":2,"title":"需求分析","slug":"需求分析","link":"#需求分析","children":[]},{"level":2,"title":"架构设计","slug":"架构设计","link":"#架构设计","children":[]}],"relativePath":"accumulation/front-end-architect.md","filePath":"accumulation/front-end-architect.md","lastUpdated":1715754557000}'),t={name:"accumulation/front-end-architect.md"},r=e('<h1 id="什么是架构师" tabindex="-1">什么是架构师 <a class="header-anchor" href="#什么是架构师" aria-label="Permalink to &quot;什么是架构师&quot;">​</a></h1><p>架构师需要深入理解需求、参与需求、看透需求背后的业务本质</p><p>架构师思维分析需求：全局思维、整体思维、闭环思维</p><p>架构师区别：充分理解业务，对业务增长负责</p><h2 id="需求分析" tabindex="-1">需求分析 <a class="header-anchor" href="#需求分析" aria-label="Permalink to &quot;需求分析&quot;">​</a></h2><p>浅层需求：表面的需求 深层需求：需求闭环，对业务增长负责</p><p>统计，分渠道统计，分享</p><h2 id="架构设计" tabindex="-1">架构设计 <a class="header-anchor" href="#架构设计" aria-label="Permalink to &quot;架构设计&quot;">​</a></h2><ul><li>分析需求需要多少项目，确定范围</li><li>需要自研统计服务</li><li>各个项目之间的关系图</li><li>数据结构设计</li><li>数据流转关系图 <ul><li>做技术方案设计，为的就是寻找一个方向，论证：可行性、扩展性、复杂度高低。不用确定细节，保证设计方向和思路是一样的就行</li></ul></li><li>写架构设计文档 <ul><li>技术方案文档的重要性</li><li>没有规范时，随性写，解释下如何做即可</li><li>可尝试写部分代码，捋一捋思路，再写文档</li><li>写设计文档不是浪费时间。写不出来正好暴露没有想明白</li><li>目录结构 <ul><li>需求：文档</li><li>范围：整体设计，架构设计，没有细节</li><li>模块设计： 模块拆分、关系图，只看结果，模块的关键功能、职责等。特殊模块重点说明</li><li>数据结构 <ul><li>结构、解释</li><li>数据流转关系图</li></ul></li><li>扩展性 <ul><li>扩展组件，数据结构层面</li><li>扩展功能</li><li>扩展配置</li></ul></li><li>开发提效 <ul><li>脚手架</li><li>组件平台</li></ul></li><li>运维保障 <ul><li>线上服务和运维服务</li><li>安全</li><li>监控报警</li><li>服务扩展性：流量大</li></ul></li></ul></li></ul></li></ul>',9),n=[r];function c(o,u,d,s,h,_){return a(),i("div",null,n)}const m=l(t,[["render",c]]);export{f as __pageData,m as default};
